from collections import deque
from itertools import combinations
class Solution:
    def minOperations(self, s, k):
        n = len(s)
        start = 0
        for i, c in enumerate(s):
            if c == '0':
                start |= (1 << i)
        if start == 0:
            return 0
        dist = {start: 0}
        dq = deque([start])
        idx = list(range(n))
        while dq:
            cur = dq.popleft()
            if cur == 0:
                return dist[cur]
            for combo in combinations(idx, k):
                nxt = cur
                for b in combo:
                    nxt ^= (1 << b)
                if nxt not in dist:
                    dist[nxt] = dist[cur] + 1
                    dq.append(nxt)
        return -1

