from collections import deque
class Solution:
    def minOperations(self, s, k):
        n = len(s)
        z = s.count('0')
        if z == 0:
            return 0
        dist = [-1] * (n + 1)
        dist[z] = 0
        dq = deque([z])
        while dq:
            cur = dq.popleft()
            if cur == 0:
                return dist[0]
            top = min(cur, k)
            for i in range(top + 1):
                if 0 <= k - i <= n - cur:
                    nz = cur - 2 * i + k
                    if 0 <= nz <= n and dist[nz] == -1:
                        dist[nz] = dist[cur] + 1
                        dq.append(nz)
        return dist[0]

