var minOperations = function(s, k) {
    const n = s.length;
    let z = 0;
    for (const c of s) if (c === '0') z++;
    if (z === 0) return 0;
    const dist = new Array(n + 1).fill(-1);
    dist[z] = 0;
    const dq = [z];
    let head = 0;
    while (head < dq.length) {
        const cur = dq[head++];
        if (cur === 0) return dist[0];
        const top = Math.min(cur, k);
        for (let i = 0; i <= top; i++) {
            if (k - i >= 0 && k - i <= n - cur) {
                const nz = cur - 2 * i + k;
                if (nz >= 0 && nz <= n && dist[nz] === -1) {
                    dist[nz] = dist[cur] + 1;
                    dq.push(nz);
                }
            }
        }
    }
    return dist[0];
};
